class Solution:
    def isEvenOddTree(self, root):
        levels = {}

        def dfs(node, depth):
            if not node:
                return
            levels.setdefault(depth, []).append(node.val)
            dfs(node.left, depth + 1)
            dfs(node.right, depth + 1)

        dfs(root, 0)
        for depth, vals in levels.items():
            if depth % 2 == 0:
                if any(v % 2 == 0 for v in vals):
                    return False
                if any(vals[i] >= vals[i + 1] for i in range(len(vals) - 1)):
                    return False
            else:
                if any(v % 2 != 0 for v in vals):
                    return False
                if any(vals[i] <= vals[i + 1] for i in range(len(vals) - 1)):
                    return False
        return True

