from collections import deque
class Solution:
    def isEvenOddTree(self, root):
        if not root:
            return True
        q = deque([root])
        level = 0
        while q:
            prev = None
            for _ in range(len(q)):
                node = q.popleft()
                val = node.val
                if level % 2 == 0:
                    if val % 2 == 0:
                        return False
                    if prev is not None and val <= prev:
                        return False
                else:
                    if val % 2 != 0:
                        return False
                    if prev is not None and val >= prev:
                        return False
                prev = val
                if node.left:
                    q.append(node.left)
                if node.right:
                    q.append(node.right)
            level += 1
        return True

