var isEvenOddTree = function(root) {
    if (!root) return true;
    let queue = [root];
    let level = 0;
    while (queue.length) {
        const next = [];
        let prev = null;
        for (const node of queue) {
            const val = node.val;
            if (level % 2 === 0) {
                if (val % 2 === 0) return false;
                if (prev !== null && val <= prev) return false;
            } else {
                if (val % 2 !== 0) return false;
                if (prev !== null && val >= prev) return false;
            }
            prev = val;
            if (node.left) next.push(node.left);
            if (node.right) next.push(node.right);
        }
        queue = next;
        level += 1;
    }
    return true;
};
